// Generated by Selenium IDE & Synchronized by Antigravity AI
const { Builder, By, Key, until } = require('selenium-webdriver');
const { allure } = require('allure-mocha/runtime');
const fs = require('fs');
const path = require('path');

describe('Full All Merger', function () {
  this.timeout(120000);
  let driver;
  const baseUrl = "https://app.sbiz-app.my.id";
  const browserName = 'firefox';

  before(async function () {
    driver = await new Builder().forBrowser(browserName).build();
    await driver.manage().window().setRect({ width: 1280, height: 800 });

    const resultsDir = path.join(__dirname, 'allure-results');
    if (!fs.existsSync(resultsDir)) fs.mkdirSync(resultsDir, { recursive: true });
    fs.writeFileSync(path.join(resultsDir, 'environment.properties'), `Browser=${browserName}\nBaseUrl=${baseUrl}`);
  });

  after(async function () {
    if (driver) await driver.quit();
  });

  async function takeEvidence(stepName) {
    await allure.step(`Evidence: ${stepName}`, async () => {
      const screenshot = await driver.takeScreenshot();
      allure.attachment(stepName, Buffer.from(screenshot, 'base64'), 'image/png');
    });
  }

  it('1. Flow Pemasok', async function () {
    allure.label('browser', browserName);
    allure.feature('Master Data');
    allure.story('Flow Pemasok');

    // Step 1 - 8: LOGIN
    await allure.step("1. Membuka halaman login", async () => await driver.get(`${baseUrl}/home/index.php`));
    await allure.step("2. Mengatur ukuran jendela browser", async () => await driver.manage().window().setRect({ width: 1280, height: 800 }));
    await allure.step("3. Menunggu kolom username", async () => await driver.wait(until.elementLocated(By.name("username")), 30000));
    await allure.step("4. Jeda sejenak sebelum input", async () => await driver.sleep(1000));
    await allure.step("5. Input Username (via Script)", async () => await driver.executeScript("document.getElementsByName('username')[0].value='admin'"));
    await allure.step("6. Input Password (via Script)", async () => await driver.executeScript("document.getElementsByName('password')[0].value='1234'"));
    await takeEvidence("Status Login Terisi");
    await allure.step("7. Klik tombol Login", async () => await driver.findElement(By.name("submit")).click());
    await allure.step("8. Jeda proses login", async () => await driver.sleep(2000));

    // Step 9 - 17: TAMBAH
    await allure.step("9. Navigasi langsung ke halaman Pemasok", async () => await driver.get(`${baseUrl}/suplier/index.php`));
    await allure.step("10. Menunggu tombol Tambah", async () => await driver.wait(until.elementLocated(By.xpath("//input[@value='TAMBAH']")), 30000));
    await takeEvidence("Halaman Pemasok");
    await allure.step("11. Klik tombol Tambah", async () => await driver.findElement(By.xpath("//input[@value='TAMBAH']")).click());
    await allure.step("12. Menunggu Form Input terbuka", async () => await driver.wait(until.elementLocated(By.name("name")), 30000));
    await allure.step("13. Jeda sebelum mengisi form", async () => await driver.sleep(1000));
    await allure.step("14. Input Nama Pemasok", async () => await driver.executeScript("document.getElementsByName('name')[0].value='Pemasok Test'"));
    await allure.step("15. Input Keterangan Pemasok", async () => await driver.executeScript("document.getElementsByName('description')[0].value='Keterangan otomatis dari script'"));
    await takeEvidence("Form Tambah Terisi");
    await allure.step("16. Simpan Pemasok Baru", async () => await driver.findElement(By.xpath("//input[@value='SIMPAN']")).click());
    await allure.step("17. Jeda setelah simpan", async () => await driver.sleep(2000));

    // Step 18 - 22: EDIT
    await allure.step("18. Cari 'Pemasok Test' dan klik Edit", async () => await driver.findElement(By.xpath("//tr[td[contains(.,'Pemasok Test')]]//input[@value='EDIT']")).click());
    await allure.step("19. Menunggu Form Edit", async () => await driver.wait(until.elementLocated(By.name("name")), 30000));
    await allure.step("20. Update Nama Pemasok", async () => await driver.executeScript("document.getElementsByName('name')[0].value='Pemasok Test Edited'"));
    await takeEvidence("Form Edit Terisi");
    await allure.step("21. Simpan Perubahan", async () => await driver.findElement(By.xpath("//input[@value='SIMPAN']")).click());
    await allure.step("22. Jeda setelah edit", async () => await driver.sleep(2000));

    // Step 23 - 26: HAPUS & LOGOUT
    await allure.step("23. Bypass popup konfirmasi hapus", async () => await driver.executeScript("window.confirm = function() { return true; }"));
    await allure.step("24. Cari 'Pemasok Test' dan klik Hapus", async () => await driver.findElement(By.xpath("//tr[td[contains(.,'Pemasok Test Edited')]]//input[@value='HAPUS']")).click());
    await takeEvidence("Data Berhasil Dihapus");
    await allure.step("25. Jeda setelah hapus", async () => await driver.sleep(2000));
    await allure.step("26. Logout dari aplikasi", async () => await driver.get(`${baseUrl}/login/signout.php`));
  });

  it('2. Flow Ekspedisi', async function () {
    allure.label('browser', browserName);
    allure.feature('Master Data');
    allure.story('Flow Ekspedisi');

    // Step 1 - 8: LOGIN
    await allure.step("1. Membuka halaman login", async () => await driver.get(`${baseUrl}/home/index.php`));
    await allure.step("2. Mengatur ukuran jendela browser", async () => await driver.manage().window().setRect({ width: 1280, height: 800 }));
    await allure.step("3. Menunggu kolom username muncul", async () => await driver.wait(until.elementLocated(By.name("username")), 30000));
    await allure.step("4. Jeda sejenak sebelum input", async () => await driver.sleep(1000));
    await allure.step("5. Input Username (via Script)", async () => await driver.executeScript("document.getElementsByName('username')[0].value='admin'"));
    await allure.step("6. Input Password (via Script)", async () => await driver.executeScript("document.getElementsByName('password')[0].value='1234'"));
    await takeEvidence("Status Login Terisi");
    await allure.step("7. Klik tombol Login", async () => await driver.findElement(By.name("submit")).click());
    await allure.step("8. Jeda proses login", async () => await driver.sleep(2000));

    // Step 9 - 17: TAMBAH
    await allure.step("9. Navigasi langsung ke halaman Ekspedisi", async () => await driver.get(`${baseUrl}/expedition/index.php`));
    await allure.step("10. Menunggu tombol Tambah", async () => await driver.wait(until.elementLocated(By.xpath("//input[@value='TAMBAH']")), 30000));
    await takeEvidence("Halaman Ekspedisi");
    await allure.step("11. Klik tombol Tambah", async () => await driver.findElement(By.xpath("//input[@value='TAMBAH']")).click());
    await allure.step("12. Menunggu Form Input terbuka", async () => await driver.wait(until.elementLocated(By.name("name")), 30000));
    await allure.step("13. Jeda sebelum mengisi form", async () => await driver.sleep(1000));
    await allure.step("14. Input Nama Ekspedisi", async () => await driver.executeScript("document.getElementsByName('name')[0].value='Test Ekspedisi'"));
    await allure.step("15. Input Keterangan Ekspedisi", async () => await driver.executeScript("document.getElementsByName('description')[0].value='Keterangan otomatis dari script'"));
    await takeEvidence("Form Tambah Terisi");
    await allure.step("16. Simpan Ekspedisi Baru", async () => await driver.findElement(By.xpath("//input[@value='SIMPAN']")).click());
    await allure.step("17. Jeda setelah simpan", async () => await driver.sleep(2000));

    // Step 18 - 22: EDIT
    await allure.step("18. Cari 'Test Ekspedisi' dan klik Edit", async () => await driver.findElement(By.xpath("//tr[td[contains(.,'Test Ekspedisi')]]//input[@value='EDIT']")).click());
    await allure.step("19. Menunggu Form Edit", async () => await driver.wait(until.elementLocated(By.name("name")), 30000));
    await allure.step("20. Update Nama Ekspedisi", async () => await driver.executeScript("document.getElementsByName('name')[0].value='Test Ekspedisi Edited'"));
    await takeEvidence("Form Edit Terisi");
    await allure.step("21. Simpan Perubahan", async () => await driver.findElement(By.xpath("//input[@value='SIMPAN']")).click());
    await allure.step("22. Jeda setelah edit", async () => await driver.sleep(2000));

    // Step 23 - 26: HAPUS & LOGOUT
    await allure.step("23. Bypass popup konfirmasi hapus", async () => await driver.executeScript("window.confirm = function() { return true; }"));
    await allure.step("24. Cari 'Test Ekspedisi' dan klik Hapus", async () => await driver.findElement(By.xpath("//tr[td[contains(.,'Test Ekspedisi Edited')]]//input[@value='HAPUS']")).click());
    await takeEvidence("Data Berhasil Dihapus");
    await allure.step("25. Jeda setelah hapus", async () => await driver.sleep(2000));
    await allure.step("26. Logout dari aplikasi", async () => await driver.get(`${baseUrl}/login/signout.php`));
  });
});
